#!/usr/bin/env node
"use strict";

/**
 * Apply engineering suggestions generated by batch-add.cjs.
 *
 * Reads:
 * - component-engineering-suggestions.json
 * - figma-e2e-batch.json
 * - ui-icon-registry.json
 *
 * Writes:
 * - optional updates to batch and icon registry (--apply)
 * - always writes an execution plan report
 *
 * Usage:
 *   node scripts/workflow/apply-engineering-suggestions.cjs
 *   node scripts/workflow/apply-engineering-suggestions.cjs --apply
 *   node scripts/workflow/apply-engineering-suggestions.cjs --mode=strict
 *   node scripts/workflow/apply-engineering-suggestions.cjs --apply --min-primitive-weight=4
 */

const fs = require("fs");
const path = require("path");
const { parseCli } = require("../cli-args.cjs");

const ROOT = process.cwd();
const FAIL_EXIT_CODE = 2;
const DEFAULT_SUGGESTIONS = "figma-cache/reports/runtime/component-engineering-suggestions.json";
const DEFAULT_BATCH = "figma-e2e-batch.json";
const DEFAULT_ICON_REGISTRY = "ui-icon-registry.json";
const DEFAULT_PLAN_OUT = "figma-cache/reports/runtime/component-engineering-apply-plan.json";

function resolveMaybeAbs(input) {
  const raw = String(input || "").trim();
  if (!raw) return "";
  return path.isAbsolute(raw) ? path.normalize(raw) : path.join(ROOT, raw);
}

function safeReadJson(absPath) {
  try {
    return JSON.parse(fs.readFileSync(absPath, "utf8"));
  } catch {
    return null;
  }
}

function writeJson(absPath, payload) {
  fs.mkdirSync(path.dirname(absPath), { recursive: true });
  fs.writeFileSync(absPath, `${JSON.stringify(payload, null, 2)}\n`, "utf8");
}

function uniqueArray(input) {
  return Array.from(new Set((Array.isArray(input) ? input : []).filter(Boolean)));
}

function slugify(input) {
  return String(input || "")
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "");
}

function normalizeNodeNameText(input) {
  const text = String(input || "").trim();
  if (!text) return "";
  const withSpaces = text.replace(/[-_]+/g, " ");
  return withSpaces
    .split(/\s+/)
    .filter(Boolean)
    .map((w) => w.charAt(0).toUpperCase() + w.slice(1))
    .join(" ");
}

function semanticKeyToFigmaNodeName(semanticKey) {
  const key = String(semanticKey || "").trim().toLowerCase();
  const overrides = {
    "general.settings": "H5 Icon/General/Settings",
    "general.arrowdown": "H5 Icon/General/Arrow-down",
    "general.checkfill": "H5 Icon/General/Check-fill",
    "general.rates": "H5 Icon/General/Rates",
    "web-calling.call-on-hold": "H5 Icon/Web Calling/Call on hold",
    "web-calling.call-recording": "H5 Icon/Web Calling/Call recording",
    "web-calling.dialpad": "H5 Icon/Web Calling/Dialpad",
    "web-calling.end-call": "H5 Icon/Web Calling/End call",
    "web-calling.minimized": "H5 Icon/Web Calling/Minimized",
    "web-calling.mute": "H5 Icon/Web Calling/Mute",
  };
  if (overrides[key]) return overrides[key];
  const parts = key.split(".").filter(Boolean);
  if (!parts.length) return "";
  if (parts.length === 2) {
    return `H5 Icon/${normalizeNodeNameText(parts[0])}/${normalizeNodeNameText(parts[1])}`;
  }
  return `H5 Icon/${parts.map((x) => normalizeNodeNameText(x)).join("/")}`;
}

function findBestRegistryEntry(entries, semanticKey, figmaNodeName) {
  const key = String(semanticKey || "").trim().toLowerCase();
  const preferredClassByKey = {
    "web-calling.minimized": "i-fluent:arrow-minimize-20-filled",
    "general.settings": "i-iconamoon:settings-fill",
    "web-calling.call-on-hold": "i-fluent:call-pause-20-filled",
    "web-calling.call-recording": "i-fluent:record-20-regular",
    "web-calling.dialpad": "i-fluent:dialpad-20-filled",
    "web-calling.end-call": "i-fluent:call-end-20-filled",
    "web-calling.mute": "i-fluent:mic-off-20-filled",
    "general.arrowdown": "i-iconamoon:arrow-down-2-light",
  };

  const byRegex = entries.find((entry) => {
    const regexList =
      entry && entry.match && Array.isArray(entry.match.figmaNodeNameRegex) ? entry.match.figmaNodeNameRegex : [];
    return regexList.some((pattern) => {
      try {
        return new RegExp(String(pattern), "i").test(figmaNodeName);
      } catch {
        return false;
      }
    });
  });
  if (byRegex) return byRegex;

  const preferredClass = preferredClassByKey[key];
  if (preferredClass) {
    const byClass = entries.find((entry) => String(entry && entry.className ? entry.className : "") === preferredClass);
    if (byClass) return byClass;
  }
  return null;
}

function inferClassNameBySemanticKey(semanticKey) {
  const key = String(semanticKey || "").trim().toLowerCase();
  const direct = {
    "general.rates": "i-lucide:badge-dollar-sign",
    "general.checkfill": "i-lucide:check",
    "general.arrowdown": "i-iconamoon:arrow-down-2-light",
    "general.settings": "i-iconamoon:settings-fill",
    "web-calling.call-on-hold": "i-fluent:call-pause-20-filled",
    "web-calling.call-recording": "i-fluent:record-20-regular",
    "web-calling.dialpad": "i-fluent:dialpad-20-filled",
    "web-calling.end-call": "i-fluent:call-end-20-filled",
    "web-calling.minimized": "i-fluent:arrow-minimize-20-filled",
    "web-calling.mute": "i-fluent:mic-off-20-filled",
  };
  if (direct[key]) return direct[key];
  if (key.includes("check")) return "i-lucide:check";
  if (key.includes("rate") || key.includes("price")) return "i-lucide:badge-dollar-sign";
  if (key.includes("setting")) return "i-iconamoon:settings-fill";
  if (key.includes("arrow") && key.includes("down")) return "i-iconamoon:arrow-down-2-light";
  return "";
}

function parseClassParts(className) {
  const m = String(className || "").match(/^i-([a-z0-9-]+):(.+)$/i);
  if (!m) return { vendor: "custom", iconName: slugify(className) || "icon" };
  return { vendor: String(m[1]).toLowerCase(), iconName: String(m[2]) };
}

function createRegistryEntry(entries, semanticKey, figmaNodeName) {
  const className = inferClassNameBySemanticKey(semanticKey);
  if (!className) return null;
  const { vendor, iconName } = parseClassParts(className);
  const semanticSlug = slugify(semanticKey).replace(/\./g, "-");
  const baseId = `${vendor}:${iconName}`;
  let id = baseId;
  let idx = 1;
  const existsId = () => entries.some((x) => String(x && x.id ? x.id : "") === id);
  while (existsId()) {
    id = `${baseId}-auto-${idx}`;
    idx += 1;
  }
  const next = {
    id,
    vendor,
    className,
    sizePx: 20,
    semantics: semanticSlug || semanticKey,
    match: {
      figmaNodeNameRegex: [`^${figmaNodeName.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")}$`],
    },
    generatedBy: "apply-engineering-suggestions.auto-create",
  };
  entries.push(next);
  return next;
}

function ensureRegexOnEntry(entry, figmaNodeName) {
  if (!entry.match || typeof entry.match !== "object") entry.match = {};
  if (!Array.isArray(entry.match.figmaNodeNameRegex)) entry.match.figmaNodeNameRegex = [];
  const wanted = `^${figmaNodeName.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")}$`;
  const normalizeRegexText = (s) => String(s || "").trim().replace(/\\\//g, "/");
  const normalizedWanted = normalizeRegexText(wanted);
  const normalizedToRaw = new Map();
  entry.match.figmaNodeNameRegex.forEach((raw) => {
    const key = normalizeRegexText(raw);
    if (!normalizedToRaw.has(key)) normalizedToRaw.set(key, String(raw || "").trim());
  });
  const existingNormalized = new Set(normalizedToRaw.keys());
  if (!existingNormalized.has(normalizedWanted)) {
    normalizedToRaw.set(normalizedWanted, wanted);
    entry.match.figmaNodeNameRegex = Array.from(normalizedToRaw.values());
    return { changed: true, regex: wanted };
  }
  entry.match.figmaNodeNameRegex = Array.from(normalizedToRaw.values());
  return { changed: false, regex: wanted };
}

function parseArgs() {
  const { values, flags, unknown } = parseCli(process.argv, {
    strings: ["suggestions", "batch", "registry", "plan-out", "min-primitive-weight", "mode"],
    booleanFlags: ["apply", "no-icon", "no-primitive", "no-auto-create-icons"],
  });
  const minWeightRaw = String(values["min-primitive-weight"] || "").trim();
  const minPrimitiveWeight = minWeightRaw && Number.isFinite(Number(minWeightRaw)) ? Number(minWeightRaw) : 3;
  const modeRaw = String(values.mode || "").trim().toLowerCase();
  const mode = modeRaw === "strict" ? "strict" : "auto";
  return {
    suggestions: String(values.suggestions || "").trim() || DEFAULT_SUGGESTIONS,
    batch: String(values.batch || "").trim() || DEFAULT_BATCH,
    registry: String(values.registry || "").trim() || DEFAULT_ICON_REGISTRY,
    planOut: String(values["plan-out"] || "").trim() || DEFAULT_PLAN_OUT,
    minPrimitiveWeight,
    mode,
    apply: Boolean(flags.apply),
    noIcon: Boolean(flags["no-icon"]),
    noPrimitive: Boolean(flags["no-primitive"]),
    noAutoCreateIcons: Boolean(flags["no-auto-create-icons"]),
    unknownArgs: unknown,
  };
}

function main() {
  const args = parseArgs();
  if (args.unknownArgs.length) {
    console.error(`Unknown args: ${args.unknownArgs.join(", ")}`);
    process.exit(FAIL_EXIT_CODE);
  }

  const allowAutoCreateIcons = args.mode !== "strict" && !args.noAutoCreateIcons;

  const suggestionsAbs = resolveMaybeAbs(args.suggestions);
  const batchAbs = resolveMaybeAbs(args.batch);
  const registryAbs = resolveMaybeAbs(args.registry);
  const planAbs = resolveMaybeAbs(args.planOut);

  const suggestions = safeReadJson(suggestionsAbs);
  const batch = safeReadJson(batchAbs);
  const registry = safeReadJson(registryAbs);
  if (!suggestions || typeof suggestions !== "object") {
    console.error(`[apply-engineering-suggestions] invalid suggestions: ${suggestionsAbs}`);
    process.exit(FAIL_EXIT_CODE);
  }
  if (!batch || typeof batch !== "object") {
    console.error(`[apply-engineering-suggestions] invalid batch: ${batchAbs}`);
    process.exit(FAIL_EXIT_CODE);
  }
  if (!registry || typeof registry !== "object") {
    console.error(`[apply-engineering-suggestions] invalid icon registry: ${registryAbs}`);
    process.exit(FAIL_EXIT_CODE);
  }

  const cases = Array.isArray(batch.cases) ? batch.cases : [];
  const registryEntries = Array.isArray(registry.entries) ? registry.entries : [];
  const suggestionRoot = suggestions && suggestions.suggestions && typeof suggestions.suggestions === "object"
    ? suggestions.suggestions
    : {};

  const iconSuggestions = Array.isArray(suggestionRoot.iconMapping) ? suggestionRoot.iconMapping : [];
  const primitiveSuggestions = Array.isArray(suggestionRoot.primitiveExtraction) ? suggestionRoot.primitiveExtraction : [];

  const iconPlan = [];
  if (!args.noIcon) {
    iconSuggestions.forEach((item) => {
      const family = String(item && item.family ? item.family : "").trim();
      const semanticKey = String(item && item.semanticKey ? item.semanticKey : "").trim();
      if (!semanticKey) return;
      const figmaNodeName = semanticKeyToFigmaNodeName(semanticKey);
      const entry = findBestRegistryEntry(registryEntries, semanticKey, figmaNodeName);
      if (!entry && allowAutoCreateIcons) {
        const created = createRegistryEntry(registryEntries, semanticKey, figmaNodeName);
        if (created) {
          iconPlan.push({
            family,
            semanticKey,
            figmaNodeName,
            className: String(created.className || ""),
            status: "auto_created",
            regex: String(
              created.match &&
                Array.isArray(created.match.figmaNodeNameRegex) &&
                created.match.figmaNodeNameRegex[0]
                ? created.match.figmaNodeNameRegex[0]
                : ""
            ),
          });
          return;
        }
      }
      if (!entry) {
        iconPlan.push({
          family,
          semanticKey,
          figmaNodeName,
          status: "manual_required",
          reason: "no_existing_registry_entry",
        });
        return;
      }
      const result = ensureRegexOnEntry(entry, figmaNodeName);
      iconPlan.push({
        family,
        semanticKey,
        figmaNodeName,
        className: String(entry.className || ""),
        status: result.changed ? "applied_or_pending" : "already_covered",
        regex: result.regex,
      });
    });
  }

  const primitivePlan = [];
  if (!args.noPrimitive) {
    const accepted = primitiveSuggestions.filter((item) => Number(item && item.weight) >= args.minPrimitiveWeight);
    const familyToNames = new Map();
    accepted.forEach((item) => {
      const family = String(item && item.family ? item.family : "").trim();
      const primitiveName = String(item && item.primitiveName ? item.primitiveName : "").trim();
      if (!family || !primitiveName) return;
      if (!familyToNames.has(family)) familyToNames.set(family, new Set());
      familyToNames.get(family).add(primitiveName);
    });

    cases.forEach((item) => {
      const family = String(item && item.naming && item.naming.family ? item.naming.family : "").trim();
      if (!family || !familyToNames.has(family)) return;
      if (!item.policy || typeof item.policy !== "object") item.policy = {};
      const before = Array.isArray(item.policy.allowPrimitives) ? item.policy.allowPrimitives : [];
      const merged = uniqueArray([...before, ...Array.from(familyToNames.get(family))]).sort();
      const changed = JSON.stringify(before) !== JSON.stringify(merged);
      if (changed) item.policy.allowPrimitives = merged;
      primitivePlan.push({
        caseId: String(item.id || ""),
        family,
        beforeCount: before.length,
        afterCount: merged.length,
        changed,
        allowPrimitives: merged,
      });
    });
  }

  if (args.apply) {
    writeJson(batchAbs, batch);
    writeJson(registryAbs, registry);
  }

  const planReport = {
    version: 1,
    generatedAt: new Date().toISOString(),
    applyMode: args.apply ? "apply" : "dry-run",
    mode: args.mode,
    inputs: {
      suggestions: path.relative(ROOT, suggestionsAbs).replace(/\\/g, "/"),
      batch: path.relative(ROOT, batchAbs).replace(/\\/g, "/"),
      registry: path.relative(ROOT, registryAbs).replace(/\\/g, "/"),
      minPrimitiveWeight: args.minPrimitiveWeight,
      allowAutoCreateIcons,
    },
    summary: {
      iconTotal: iconPlan.length,
      iconManualRequired: iconPlan.filter((x) => x.status === "manual_required").length,
      iconChanged: iconPlan.filter((x) => x.status === "applied_or_pending").length,
      iconAutoCreated: iconPlan.filter((x) => x.status === "auto_created").length,
      primitiveTotal: primitivePlan.length,
      primitiveChangedCases: primitivePlan.filter((x) => x.changed).length,
    },
    plan: {
      iconMapping: iconPlan,
      primitiveAllowList: primitivePlan,
    },
  };
  writeJson(planAbs, planReport);

  console.log(
    `[apply-engineering-suggestions] ok run=${args.apply ? "apply" : "dry-run"} mode=${args.mode} icon=${planReport.summary.iconTotal} primitiveCases=${planReport.summary.primitiveTotal}`
  );
}

main();
